1	/** A live cell's position on the infinite grid, as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
5	  [-1, -1], [0, -1], [1, -1],
6	  [-1,  0],          [1,  0],
7	  [-1,  1], [0,  1], [1,  1],
8	];
9	
10	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
11	
12	const neighborsOf = ([x, y]: Cell): Cell[] =>
13	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
14	
15	const livesNextGeneration = (isAlive: boolean, liveNeighborCount: number): boolean =>
16	  liveNeighborCount === 3 || (isAlive && liveNeighborCount === 2);
17	
18	/**
19	 * Computes the live cells of the next generation of Conway's Game of Life
20	 * from the current set of live cells.
21	 */
22	export function nextGeneration(liveCells: Cell[]): Cell[] {
23	  const liveKeys = new Set(liveCells.map(cellKey));
24	  const candidates = new Map<string, Cell>();
25	  const liveNeighborCounts = new Map<string, number>();
26	
27	  for (const live of liveCells) {
28	    for (const neighbor of neighborsOf(live)) {
29	      const key = cellKey(neighbor);
30	      candidates.set(key, neighbor);
31	      liveNeighborCounts.set(key, (liveNeighborCounts.get(key) ?? 0) + 1);
32	    }
33	  }
34	
35	  const survivors: Cell[] = [];
36	  for (const [key, cell] of candidates) {
37	    const count = liveNeighborCounts.get(key) ?? 0;
38	    if (livesNextGeneration(liveKeys.has(key), count)) {
39	      survivors.push(cell);
40	    }
41	  }
42	  return survivors;
43	}
